  ('social-worker-moex-01151', 'social-worker', 'social-worker-moex-110-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某機構統計過去三年收到的捐款資料，發現小額捐款比例逐年降低，機構想了解原因，遂指派一 位社工員進行研究，這位社工員撰寫研究計畫時，提出的研究問題應該是什麼？', '["小額捐款者的年齡與背景因素", "小額捐款減少的相關因素", "機構服務成效與責信關係", "影響機構服務成效的相關因素"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "b103121a72fe", "answer_pdf_sha1": "6d5b6600baad", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
